      "supporting_facts": "Can present with rapidly progressive cognitive decline and limbic involvement.",
      "opposing_facts": "Screening serology was negative, making this highly unlikely.",
      "support_level": "Unsupported"
    },
    "Autoimmune encephalitis (non-paraneoplastic)": {
      "supporting_facts": "Limbic MRI changes, CSF oligoclonal bands, and seizures.",
      "opposing_facts": "None; must be considered in the differential.",
      "support_level": "Well-supported"
    },
    "Creutzfeldt-Jakob disease": {
      "supporting_facts": "Rapidly progressive dementia.",
      "opposing_facts": "MRI is more suggestive of inflammation (confluent signal) rather than the restricted diffusion typically seen in CJD; prolonged duration (5+ months).",
      "support_level": "Weakly supported"
    }
  },
